#!/bin/bash
# Runs one Percy snapshot pass (one JS mode × one phase) and emits per-snapshot
# diffs inline. Reusable across baseline + comparison phases, JS=enabled +
# JS=disabled.
#
# Args:
#   $1  JS mode:    enabled | disabled
#   $2  phase:      baseline | comparison
#   $3  run index:  0 for baseline, 1..N for comparisons (default 0)
#
# Reads from BK meta-data (set by Step 1 / create-projects.js):
#   PERCY_TOKEN_JS_<UPPER_JS>       full-access (master) token for the target Percy project
#   BASELINE_COMMIT                 synthetic 40-char SHA generated by cycle-step1.sh
#
# Baseline-pinning convention (all builds run on PERCY_BRANCH=master):
#   baseline        -> PERCY_COMMIT=$BASELINE_COMMIT  (tags the anchor build)
#   comparison  N   -> PERCY_COMMIT=<unique per run>, PERCY_TARGET_COMMIT=$BASELINE_COMMIT
#                      (pins every comparison against the same baseline so diffs don't chain)
#
# For parallel comparison fan-out, each run sleeps RUN_INDEX * 30s before
# `percy exec` to stagger start times — preserves temporal flake signal across
# the 5 runs without serializing the wall clock.
#
# Side effects:
#   - runs `npx percy exec -- playwright test` against 25 URLs
#   - tees output to .percy-run-$JS-$PHASE[-$RUN_INDEX].log
#   - extracts Percy build ID, sets BK meta-data
#       PERCY_BUILD_ID_<UPPER_JS>_BASELINE                      (phase=baseline)
#       PERCY_BUILD_ID_<UPPER_JS>_COMPARISON_<RUN_INDEX>        (phase=comparison)
#   - waits for Percy build to finalize (state=finished) before exiting

set -euo pipefail

# Ensure Node 20 is present on whichever BK agent picked up this step.
# `nvm install` is idempotent: installs if missing, no-op if present, always activates.
if [ -s "${HOME}/.nvm/nvm.sh" ]; then
  # shellcheck disable=SC1091
  source "${HOME}/.nvm/nvm.sh"
  nvm install 20
  nvm use 20
fi

JS="${1:?JS arg required (enabled|disabled)}"
PHASE="${2:?PHASE arg required (baseline|comparison)}"
RUN_INDEX="${3:-0}"

UPPER_JS=$(echo "$JS" | tr '[:lower:]' '[:upper:]')
UPPER_PHASE=$(echo "$PHASE" | tr '[:lower:]' '[:upper:]')

TOKEN_KEY="PERCY_TOKEN_JS_${UPPER_JS}"

# Full-access (master) token — used by both `percy exec` for upload and
# `fetch-diffs.js` for GET /snapshots.
export PERCY_TOKEN=$(buildkite-agent meta-data get "$TOKEN_KEY")
BASELINE_COMMIT=$(buildkite-agent meta-data get BASELINE_COMMIT)
if [ -z "${BASELINE_COMMIT:-}" ]; then
  echo "ERROR: BASELINE_COMMIT meta-data not set by cycle-step1.sh" >&2
  exit 2
fi

# All builds sit on master in Percy history; baseline-pinning is done via
# PERCY_TARGET_COMMIT (overrides branch-based base-build selection).
export PERCY_BRANCH="master"

case "$PHASE" in
  baseline)
    export PERCY_COMMIT="$BASELINE_COMMIT"
    META_KEY="PERCY_BUILD_ID_${UPPER_JS}_BASELINE"
    LOG=".percy-run-${JS}-${PHASE}.log"
    ;;
  comparison)
    if [ "$RUN_INDEX" = "0" ]; then
      echo "ERROR: comparison phase requires RUN_INDEX >= 1" >&2
      exit 2
    fi
    # Unique SHA per run so Percy treats each comparison as its own build while
    # every one of them resolves PERCY_TARGET_COMMIT back to the single baseline.
    PERCY_COMMIT_VALUE=$(printf 'comparison-cycle-%s-run-%s-%s-%s' \
      "$(buildkite-agent meta-data get CYCLE_ID)" "$RUN_INDEX" "$JS" "$$" \
      | shasum | awk '{print $1}')
    export PERCY_COMMIT="$PERCY_COMMIT_VALUE"
    export PERCY_TARGET_COMMIT="$BASELINE_COMMIT"
    META_KEY="PERCY_BUILD_ID_${UPPER_JS}_COMPARISON_${RUN_INDEX}"
    LOG=".percy-run-${JS}-${PHASE}-${RUN_INDEX}.log"

    # Temporal spread across parallel comparison runs. Two goals:
    #   1. Preserve flake signal on live URLs (temporal variance across runs)
    #   2. Avoid saturating Percy's server-side render queue when JS=enabled
    #      (JS=enabled renders are ~10-30s per snapshot × 25 × browsers ≈ 100
    #      heavy tasks per build; 5 concurrent JS=enabled builds caused Percy
    #      backend to fail 2/5 runs in cycle #133). JS=disabled renders are
    #      trivial on the server, so keep the tight 30s spread there.
    if [ "$JS" = "enabled" ]; then
      JITTER=$(( RUN_INDEX * 90 ))
    else
      JITTER=$(( RUN_INDEX * 30 ))
    fi
    echo "=== Jitter sleep ${JITTER}s (run ${RUN_INDEX} of ${PHASE}, JS=${JS}) ==="
    sleep "$JITTER"
    ;;
  *)
    echo "ERROR: PHASE must be 'baseline' or 'comparison', got: $PHASE" >&2
    exit 2
    ;;
esac

echo "=== Mode: JS=${JS}, Phase: ${PHASE}, RunIndex: ${RUN_INDEX}, PERCY_BRANCH: ${PERCY_BRANCH}, PERCY_COMMIT: ${PERCY_COMMIT}, PERCY_TARGET_COMMIT: ${PERCY_TARGET_COMMIT:-<unset>} ==="

rm -rf .percy.yml test-results/ playwright-report/
cp ".percy.js-${JS}.yml" .percy.yml
echo "=== Active Percy config ==="
cat .percy.yml

npm ci
npx percy --version
npx playwright install --with-deps chromium

# Belt-and-suspenders: if any single URL fails to reach network-idle within
# Percy's internal renderer timeout, capture the snapshot anyway instead of
# failing the whole build. Observed on #128/#129 where figma-home + nasa-home
# hung the renderer and took down otherwise-clean baselines.
export PERCY_IGNORE_TIMEOUT_ERROR=true

npx percy exec -- npx playwright test tests/percy_web.spec.js --reporter=dot 2>&1 | tee "$LOG"

# Strip ANSI escapes; extract last builds/<digits> occurrence as Percy build ID.
sed -r 's/\x1B\[[0-9;]*[a-zA-Z]//g' "$LOG" > "$LOG.clean"
PERCY_BUILD_ID=$(grep -oE 'builds/[0-9]+' "$LOG.clean" | tail -1 | cut -d/ -f2 || true)

if [ -n "${PERCY_BUILD_ID:-}" ]; then
  echo ""
  echo "=== Percy build id: ${PERCY_BUILD_ID} ==="
  buildkite-agent meta-data set "$META_KEY" "$PERCY_BUILD_ID"

  echo ""
  echo "=== Waiting for Percy build ${PERCY_BUILD_ID} to finalize (server-side processing) ==="
  # `percy exec` returns after upload+finalize API calls; Percy then runs
  # rendering + diff asynchronously. Poll until state=finished so that when
  # BK's `wait` lifts between groups, both builds are truly done.
  # Cross-agent settle buffers (30s after baselines, 10s after comparisons)
  # are handled by dedicated pipeline steps, not here.
  node bin/wait-for-build.js --build-id="$PERCY_BUILD_ID" --token="$PERCY_TOKEN" --post-sleep-seconds=0
else
  echo "WARN: could not extract Percy build ID from ${LOG}"
  echo "--- last 20 lines of ${LOG} for debugging: ---"
  tail -20 "$LOG" || true
fi
